content.content:
  1→import { randomUUID } from "node:crypto";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { EntityCategory, ObservationSeverity, ObservationStatus, ObservationSummary } from "../../shared/contracts";
  4→
  5→type ObservationRecord = RecordId<"observation", string>;
  6→type ObserveTargetRecord = RecordId<"project" | "feature" | "task" | "decision" | "question", string>;
  7→
  8→const SEVERITY_PRIORITY: Record<ObservationSeverity, number> = {
  9→  conflict: 0,
 10→  warning: 1,
 11→  info: 2,
 12→};
 13→
 14→export async function createObservation(input: {
 15→  surreal: Surreal;
 16→  workspaceRecord: RecordId<"workspace", string>;
 17→  text: string;
 18→  severity: ObservationSeverity;
 19→  category?: EntityCategory;
 20→  sourceAgent: string;
 21→  now: Date;
 22→  sourceMessageRecord?: RecordId<"message", string>;
 23→  relatedRecord?: ObserveTargetRecord;
 24→  embedding?: number[];
 25→}): Promise<ObservationRecord> {
 26→  const observationRecord = new RecordId("observation", randomUUID());
 27→
 28→  await input.surreal.create(observationRecord).content({
 29→    text: input.text,
 30→    severity: input.severity,
 31→    status: "open",
 32→    ...(input.category ? { category: input.category } : {}),
 33→    source_agent: input.sourceAgent,
 34→    workspace: input.workspaceRecord,
 35→    ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
 36→    ...(input.embedding ? { embedding: input.embedding } : {}),
 37→    created_at: input.now,
 38→    updated_at: input.now,
 39→  });
 40→
 41→  if (input.relatedRecord) {
 42→    await input.surreal
 43→      .relate(observationRecord, new RecordId("observes", randomUUID()), input.relatedRecord, {
 44→        added_at: input.now,
 45→      })
 46→      .output("after");
 47→  }
 48→
 49→  return observationRecord;
 50→}
 51→
 52→export async function acknowledgeObservation(input: {
 53→  surreal: Surreal;
 54→  workspaceRecord: RecordId<"workspace", string>;
 55→  observationRecord: ObservationRecord;
 56→  now: Date;
 57→}): Promise<void> {
 58→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 59→  if (!row) {
 60→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 61→  }
 62→
 63→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 64→    throw new Error("observation is outside the current workspace scope");
 65→  }
 66→
 67→  await input.surreal.update(input.observationRecord).merge({
 68→    status: "acknowledged" satisfies ObservationStatus,
 69→    updated_at: input.now,
 70→  });
 71→}
 72→
 73→export async function resolveObservation(input: {
 74→  surreal: Surreal;
 75→  workspaceRecord: RecordId<"workspace", string>;
 76→  observationRecord: ObservationRecord;
 77→  now: Date;
 78→  resolvedByRecord?: RecordId<"person", string>;
 79→}): Promise<void> {
 80→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
 81→  if (!row) {
 82→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
 83→  }
 84→
 85→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 86→    throw new Error("observation is outside the current workspace scope");
 87→  }
 88→
 89→  await input.surreal.update(input.observationRecord).merge({
 90→    status: "resolved" satisfies ObservationStatus,
 91→    resolved_at: input.now,
 92→    ...(input.resolvedByRecord ? { resolved_by: input.resolvedByRecord } : {}),
 93→    updated_at: input.now,
 94→  });
 95→}
 96→
 97→export async function listWorkspaceOpenObservations(input: {
 98→  surreal: Surreal;
 99→  workspaceRecord: RecordId<"workspace", string>;
100→  limit: number;
101→}): Promise<ObservationSummary[]> {
102→  const [rows] = await input.surreal
103→    .query<[
104→      Array<{
105→        id: ObservationRecord;
106→        text: string;
107→        severity: ObservationSeverity;
108→        status: ObservationStatus;
109→        category?: EntityCategory;
110→        source_agent: string;
111→        created_at: string | Date;
112→      }>,
113→    ]>(
114→      [
115→        "SELECT id, text, severity, status, category, source_agent, created_at",
116→        "FROM observation",
117→        "WHERE workspace = $workspace",
118→        "AND status IN ['open', 'acknowledged']",
119→        "ORDER BY created_at DESC",
120→        "LIMIT $limit;",
121→      ].join(" "),
122→      {
123→        workspace: input.workspaceRecord,
124→        limit: input.limit,
125→      },
126→    )
127→    .collect<[
128→      Array<{
129→        id: ObservationRecord;
130→        text: string;
131→        severity: ObservationSeverity;
132→        status: ObservationStatus;
133→        category?: EntityCategory;
134→        source_agent: string;
135→        created_at: string | Date;
136→      }>,
137→    ]>();
138→
139→  return rows
140→    .slice()
141→    .sort((a, b) => {
142→      const severityDelta = SEVERITY_PRIORITY[a.severity] - SEVERITY_PRIORITY[b.severity];
143→      if (severityDelta !== 0) {
144→        return severityDelta;
145→      }
146→
147→      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
148→    })
149→    .map((row) => ({
150→      id: row.id.id as string,
151→      text: row.text,
152→      severity: row.severity,
153→      status: row.status,
154→      ...(row.category ? { category: row.category } : {}),
155→      sourceAgent: row.source_agent,
156→      createdAt: row.created_at instanceof Date ? row.created_at.toISOString() : new Date(row.created_at).toISOString(),
157→    }));
158→}
159→

