content.content:
  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import type {
  4→  CreateWorkspaceResponse,
  5→  OnboardingSeedItem,
  6→  WorkspaceBootstrapMessage,
  7→  WorkspaceBootstrapResponse,
  8→  WorkspaceConversationResponse,
  9→  SourceKind,
 10→  EntityKind,
 11→} from "../../shared/contracts";
 12→import { createEmbeddingVector } from "../graph/embeddings";
 13→import { readEntityText } from "../extraction/entity-text";
 14→import type { GraphEntityRecord, SourceRecord } from "../extraction/types";
 15→import { HttpError } from "../http/errors";
 16→import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
 17→import { parseCreateWorkspaceRequest } from "../http/parsing";
 18→import { jsonError, jsonResponse, toIsoString } from "../http/response";
 19→import type { ServerDependencies } from "../runtime/types";
 20→import { toOnboardingState } from "../onboarding/onboarding-state";
 21→import { resolveWorkspaceRecord } from "./workspace-scope";
 22→import { buildWorkspaceConversationSidebar } from "./conversation-sidebar";
 23→import { loadMessagesWithInheritance } from "../chat/branch-chain";
 24→
 25→type WorkspaceRow = {
 26→  id: RecordId<"workspace", string>;
 27→  name: string;
 28→  status: string;
 29→  onboarding_complete: boolean;
 30→  onboarding_turn_count: number;
 31→  onboarding_summary_pending: boolean;
 32→};
 33→
 34→type ProvenanceEdgeRow = {
 35→  id: RecordId<"extraction_relation", string>;
 36→  in: SourceRecord;
 37→  out: GraphEntityRecord;
 38→  confidence: number;
 39→  extracted_at: Date | string;
 40→};
 41→
 42→export function createWorkspaceRouteHandlers(deps: ServerDependencies): {
 43→  handleCreateWorkspace: (request: Request) => Promise<Response>;
 44→  handleWorkspaceBootstrap: (workspaceId: string) => Promise<Response>;
 45→  handleWorkspaceSidebar: (workspaceId: string) => Promise<Response>;
 46→  handleWorkspaceConversation: (workspaceId: string, conversationId: string) => Promise<Response>;
 47→} {
 48→  return {
 49→    handleCreateWorkspace: (request: Request) => handleCreateWorkspace(deps, request),
 50→    handleWorkspaceBootstrap: (workspaceId: string) => handleWorkspaceBootstrap(deps, workspaceId),
 51→    handleWorkspaceSidebar: (workspaceId: string) => handleWorkspaceSidebar(deps, workspaceId),
 52→    handleWorkspaceConversation: (workspaceId: string, conversationId: string) =>
 53→      handleWorkspaceConversation(deps, workspaceId, conversationId),
 54→  };
 55→}
 56→
 57→async function handleCreateWorkspace(deps: ServerDependencies, request: Request): Promise<Response> {
 58→  const startedAt = performance.now();
 59→  logInfo("workspace.create.started", "Workspace creation started");
 60→
 61→  let body: unknown;
 62→  try {
 63→    body = await request.json();
 64→  } catch {
 65→    return jsonError("Request body must be valid JSON", 400);
 66→  }
 67→
 68→  const parsed = parseCreateWorkspaceRequest(body);
 69→  if (!parsed.ok) {
 70→    return jsonError(parsed.error, 400);
 71→  }
 72→
 73→  logDebug("http.request.validated", "Workspace request validated");
 74→
 75→  const now = new Date();
 76→  const workspaceId = randomUUID();
 77→  const conversationId = randomUUID();
 78→  const ownerId = randomUUID();
 79→
 80→  const workspaceRecord = new RecordId("workspace", workspaceId);
 81→  const conversationRecord = new RecordId("conversation", conversationId);
 82→  const ownerRecord = new RecordId("person", ownerId);
 83→  const starterMessageRecord = new RecordId("message", randomUUID());
 84→  const starterSuggestions = [
 85→    "Describe your primary project and goal",
 86→    "Share the biggest current bottleneck",
 87→    "Upload a plan or spec to extract",
 88→  ];
 89→
 90→  const starterMessage = [
 91→    `Hey ${parsed.data.ownerDisplayName}!`,
 92→    "I'm ready to help you build out your workspace.",
 93→    "Tell me about what you're working on - what's the main project or business you want to track here?",
 94→    "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
 95→  ].join(" ");
 96→
 97→  const transaction = await deps.surreal.beginTransaction();
 98→  try {
 99→    await transaction.create(workspaceRecord).content({
100→      name: parsed.data.name,
101→      status: "active",
102→      onboarding_complete: false,
103→      onboarding_turn_count: 0,
104→      onboarding_summary_pending: false,
105→      onboarding_started_at: now,
106→      created_at: now,
107→      updated_at: now,
108→    });
109→
110→    const ownerEmbedding = await createEmbeddingVector(
111→      deps.embeddingModel,
112→      parsed.data.ownerDisplayName,
113→      deps.config.embeddingDimension,
114→    );
115→    await transaction.create(ownerRecord).content({
116→      name: parsed.data.ownerDisplayName,
117→      ...(ownerEmbedding ? { embedding: ownerEmbedding } : {}),
118→      created_at: now,
119→      updated_at: now,
120→    });
121→
122→    await transaction.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
123→      role: "owner",
124→      added_at: now,
125→    }).output("after");
126→
127→    await transaction.create(conversationRecord).content({
128→      createdAt: now,
129→      updatedAt: now,
130→      workspace: workspaceRecord,
131→      source: "onboarding",
132→      title: "Onboarding",
133→      title_source: "message",
134→    });
135→
136→    await transaction.create(starterMessageRecord).content({
137→      conversation: conversationRecord,
138→      role: "assistant",
139→      text: starterMessage,
140→      suggestions: starterSuggestions,
141→      createdAt: now,
142→    });
143→
144→    await transaction.commit();
145→  } catch (error) {
146→    await transaction.cancel();
147→    logError("workspace.create.failed", "Workspace creation failed", error, {
148→      workspaceId,
149→      conversationId,
150→    });
151→    const errorText = error instanceof Error ? error.message : "workspace creation failed";
152→    return jsonError(errorText, 500);
153→  }
154→
155→  const response: CreateWorkspaceResponse = {
156→    workspaceId,
157→    workspaceName: parsed.data.name,
158→    conversationId,
159→    onboardingComplete: false,
160→  };
161→
162→  logInfo("workspace.create.completed", "Workspace creation completed", {
163→    workspaceId,
164→    conversationId,
165→    durationMs: elapsedMs(startedAt),
166→  });
167→
168→  return jsonResponse(response, 200);
169→}
170→
171→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
172→  const startedAt = performance.now();
173→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
174→
175→  try {
176→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
177→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
178→    if (!workspace) {
179→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
180→    }
181→
182→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
183→    const conversationId = conversationRecord.id as string;
184→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
185→
186→    const messages = rawMessages.map((row) => ({
187→      id: row.id,
188→      role: row.role,
189→      text: row.text,
190→      createdAt: toIsoString(row.createdAt),
191→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
192→      ...(row.inherited ? { inherited: true } : {}),
193→    } satisfies WorkspaceBootstrapMessage));
194→
195→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
196→    const onboardingState = toOnboardingState(workspace);
197→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
198→
199→    const payload: WorkspaceBootstrapResponse = {
200→      workspaceId: workspace.id.id as string,
201→      workspaceName: workspace.name,
202→      onboardingComplete: workspace.onboarding_complete,
203→      onboardingState,
204→      conversationId: conversationRecord.id as string,
205→      messages,
206→      seeds,
207→      sidebar,
208→    };
209→
210→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
211→      workspaceId,
212→      conversationId: conversationRecord.id as string,
213→      messageCount: messages.length,
214→      seedCount: seeds.length,
215→      durationMs: elapsedMs(startedAt),
216→    });
217→
218→    return jsonResponse(payload, 200);
219→  } catch (error) {
220→    if (error instanceof HttpError) {
221→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
222→        workspaceId,
223→        statusCode: error.status,
224→      });
225→      return jsonError(error.message, error.status);
226→    }
227→
228→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
229→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
230→    return jsonError(errorText, 500);
231→  }
232→}
233→
234→async function resolveWorkspaceBootstrapConversation(
235→  deps: ServerDependencies,
236→  workspaceRecord: RecordId<"workspace", string>,
237→): Promise<RecordId<"conversation", string>> {
238→  const [onboardingRows] = await deps.surreal
239→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
240→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
241→      {
242→        workspace: workspaceRecord,
243→      },
244→    )
245→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
246→
247→  if (onboardingRows.length > 0) {
248→    return onboardingRows[0].id;
249→  }
250→
251→  const [latestRows] = await deps.surreal
252→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
253→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
254→      {
255→        workspace: workspaceRecord,
256→      },
257→    )
258→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
259→
260→  if (latestRows.length > 0) {
261→    return latestRows[0].id;
262→  }
263→
264→  const now = new Date();
265→  const conversationRecord = new RecordId("conversation", randomUUID());
266→  await deps.surreal.create(conversationRecord).content({
267→    createdAt: now,
268→    updatedAt: now,
269→    workspace: workspaceRecord,
270→    source: "onboarding",
271→  });
272→  return conversationRecord;
273→}
274→
275→async function loadWorkspaceSeeds(
276→  deps: ServerDependencies,
277→  workspaceRecord: RecordId<"workspace", string>,
278→  limit: number,
279→): Promise<OnboardingSeedItem[]> {
280→  const [edgeRows] = await deps.surreal
281→    .query<[ProvenanceEdgeRow[]]>(
282→      [
283→        "SELECT id, `in`, out, confidence, extracted_at",
284→        "FROM extraction_relation",
285→        "WHERE `in` IN array::concat(",
286→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
287→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
288→        ")",
289→        "ORDER BY extracted_at DESC",
290→        "LIMIT $limit;",
291→      ].join(" "),
292→      {
293→        workspace: workspaceRecord,
294→        limit,
295→      },
296→    )
297→    .collect<[ProvenanceEdgeRow[]]>();
298→
299→  const items: OnboardingSeedItem[] = [];
300→
301→  for (const edge of edgeRows) {
302→    const entityText = await readEntityText(deps.surreal, edge.out);
303→    if (!entityText) {
304→      continue;
305→    }
306→
307→    const sourceTable = edge.in.tb;
308→    const entityTable = edge.out.tb;
309→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
310→    const sourceLabel = await readSourceLabel(deps, edge.in);
311→
312→    items.push({
313→      id: edge.out.id as string,
314→      kind: entityTable as EntityKind,
315→      text: entityText,
316→      confidence: edge.confidence,
317→      sourceKind,
318→      sourceId: edge.in.id as string,
319→      ...(sourceLabel ? { sourceLabel } : {}),
320→    });
321→  }
322→
323→  return items;
324→}
325→
326→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
327→  const sourceTable = sourceRecord.tb;
328→  if (sourceTable === "message") {
329→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
330→    if (!row) {
331→      return undefined;
332→    }
333→    return row.text.slice(0, 140);
334→  }
335→
336→  const chunk = await deps.surreal.select<{
337→    section_heading?: string;
338→    document: RecordId<"document", string>;
339→  }>(sourceRecord);
340→
341→  if (!chunk) {
342→    return undefined;
343→  }
344→
345→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
346→  if (!document) {
347→    return chunk.section_heading;
348→  }
349→
350→  if (chunk.section_heading) {
351→    return `${document.name} · ${chunk.section_heading}`;
352→  }
353→
354→  return document.name;
355→}
356→
357→async function handleWorkspaceSidebar(deps: ServerDependencies, workspaceId: string): Promise<Response> {
358→  const startedAt = performance.now();
359→  logInfo("workspace.sidebar.started", "Workspace sidebar request started", { workspaceId });
360→
361→  try {
362→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
363→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
364→
365→    logInfo("workspace.sidebar.completed", "Workspace sidebar request completed", {
366→      workspaceId,
367→      groupCount: sidebar.groups.length,
368→      unlinkedCount: sidebar.unlinked.length,
369→      durationMs: elapsedMs(startedAt),
370→    });
371→
372→    return jsonResponse(sidebar, 200);
373→  } catch (error) {
374→    if (error instanceof HttpError) {
375→      logWarn("workspace.sidebar.http_error", "Workspace sidebar failed with client-facing error", {
376→        workspaceId,
377→        statusCode: error.status,
378→      });
379→      return jsonError(error.message, error.status);
380→    }
381→
382→    logError("workspace.sidebar.failed", "Workspace sidebar request failed", error, { workspaceId });
383→    const errorText = error instanceof Error ? error.message : "workspace sidebar failed";
384→    return jsonError(errorText, 500);
385→  }
386→}
387→
388→async function handleWorkspaceConversation(
389→  deps: ServerDependencies,
390→  workspaceId: string,
391→  conversationId: string,
392→): Promise<Response> {
393→  const startedAt = performance.now();
394→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
395→    workspaceId,
396→    conversationId,
397→  });
398→
399→  try {
400→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
401→    const conversationRecord = new RecordId("conversation", conversationId);
402→    const conversation = await deps.surreal.select<{
