405→    }>(conversationRecord);
406→
407→    if (!conversation) {
408→      throw new HttpError(404, `conversation not found: ${conversationId}`);
409→    }
410→
411→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
