149→export function parseRecordIdString<T extends string>(
150→  value: string,
151→  allowedTables: T[],
152→  fallbackTable?: T,
153→): RecordId<T, string> {
154→  const normalized = value.trim();
155→  if (normalized.length === 0) {
156→    throw new Error("record id is required");
157→  }
158→
159→  const separatorIndex = normalized.indexOf(":");
160→  if (separatorIndex === -1) {
161→    if (!fallbackTable) {
162→      throw new Error(`record id must be prefixed with one of: ${allowedTables.join(", ")}`);
163→    }
164→
165→    return new RecordId(fallbackTable, normalized) as RecordId<T, string>;
166→  }
167→
168→  const table = normalized.slice(0, separatorIndex) as T;
169→  const id = normalized.slice(separatorIndex + 1);
170→  if (!allowedTables.includes(table)) {
171→    throw new Error(`record id table must be one of: ${allowedTables.join(", ")}`);
172→  }
173→
174→  if (id.length === 0) {
175→    throw new Error("record id is missing its identifier component");
176→  }
177→
178→  return new RecordId(table, id) as RecordId<T, string>;
179→}
