317→export async function listConversationEntities(input: {
318→  surreal: Surreal;
319→  conversationRecord: RecordId<"conversation", string>;
320→  workspaceRecord: RecordId<"workspace", string>;
321→  limit: number;
322→  inheritedEntityIds?: RecordId[];
323→}): Promise<ConversationEntity[]> {
324→  const [rows] = await input.surreal
325→    .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
326→      [
327→        "SELECT `in`, out, confidence, extracted_at",
328→        "FROM extraction_relation",
329→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
330→        "ORDER BY extracted_at DESC",
331→        "LIMIT $limit;",
332→      ].join(" "),
333→      {
334→        conversation: input.conversationRecord,
335→        limit: input.limit,
336→      },
337→    )
338→    .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>() ;
339→
340→  const items: ConversationEntity[] = [];
341→  const seen = new Set<string>();
342→
343→  for (const row of rows) {
344→    const table = row.out.table.name as GraphEntityTable;
345→    if (
346→      table !== "workspace" &&
347→      table !== "project" &&
348→      table !== "person" &&
349→      table !== "feature" &&
350→      table !== "task" &&
351→      table !== "decision" &&
352→      table !== "question"
353→    ) {
354→      continue;
355→    }
356→
357→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, row.out);
358→    if (!scoped) {
359→      continue;
360→    }
361→
362→    const entityKey = `${table}:${toRecordIdString(row.out)}`;
363→    if (seen.has(entityKey)) {
364→      continue;
365→    }
366→
367→    const name = await readEntityName(input.surreal, row.out);
368→    if (!name) {
369→      continue;
370→    }
371→
372→    items.push({
373→      id: toRecordIdString(row.out),
374→      kind: table,
375→      name,
376→      confidence: row.confidence,
377→      sourceMessageId: toRecordIdString(row.in),
378→    });
379→    seen.add(entityKey);
380→  }
381→
382→  // Merge inherited entities from parent conversation when branch has sparse context
383→  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
384→    const [inheritedRows] = await input.surreal
385→      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
386→        [
387→          "SELECT `in`, out, confidence, extracted_at",
388→          "FROM extraction_relation",
389→          "WHERE out IN $entityIds",
390→          "ORDER BY extracted_at DESC",
391→          "LIMIT $limit;",
392→        ].join(" "),
393→        { entityIds: input.inheritedEntityIds, limit: input.limit },
394→      )
395→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
396→
397→    for (const row of inheritedRows) {
398→      const table = row.out.table.name as GraphEntityTable;
399→      if (
400→        table !== "workspace" &&
401→        table !== "project" &&
402→        table !== "person" &&
403→        table !== "feature" &&
404→        table !== "task" &&
405→        table !== "decision" &&
406→        table !== "question"
407→      ) {
408→        continue;
409→      }
410→
411→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
412→      if (seen.has(entityKey)) continue;
413→
414→      const name = await readEntityName(input.surreal, row.out);
415→      if (!name) continue;
416→
417→      items.push({
418→        id: toRecordIdString(row.out),
419→        kind: table,
420→        name,
421→        confidence: row.confidence,
422→        sourceMessageId: toRecordIdString(row.in),
