 614→                  ...session,
 615→                  conversations: session.conversations.map((conversation) =>
 616→                    conversation.id === clientMessageId
 617→                      ? {
 618→                          ...conversation,
 619→                          response: streamedText,
 620→                          updatedAt: new Date(),
 621→                        }
 622→                      : conversation,
 623→                  ),
 624→                }
 625→              : session,
 626→          ),
 627→        );
 628→        return;
 629→      }
 630→
 631→      if (parsed.type === "extraction") {
 632→        setSeedItems((existing) => {
 633→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
 634→          for (const entity of parsed.entities) {
 635→            const key = `${entity.id}:${entity.sourceKind}:${entity.sourceId}`;
 636→            if (!deduped.has(key)) {
 637→              deduped.set(key, {
 638→                id: entity.id,
 639→                kind: entity.kind,
 640→                text: entity.text,
 641→                confidence: entity.confidence,
 642→                sourceKind: entity.sourceKind,
 643→                sourceId: entity.sourceId,
 644→              });
 645→            }
 646→          }
 647→          return [...deduped.values()];
 648→        });
 649→        return;
 650→      }
 651→
 652→      if (parsed.type === "assistant_message") {
 653→        streamedText = parsed.text;
 654→        setSuggestions(
 655→          (parsed.suggestions ?? []).map((content, index) => ({
 656→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
 657→            content,
 658→          })),
 659→        );
 660→        setSessions((existing) =>
 661→          existing.map((session) =>
 662→            session.id === activeSessionId
 663→              ? {
 664→                  ...session,
 665→                  conversations: session.conversations.map((conversation) =>
 666→                    conversation.id === clientMessageId
 667→                      ? {
 668→                          ...conversation,
 669→                          response: streamedText,
 670→                          updatedAt: new Date(),
 671→                        }
 672→                      : conversation,
 673→                  ),
 674→                }
 675→              : session,
 676→          ),
 677→        );
 678→        return;
 679→      }
 680→
 681→      if (parsed.type === "onboarding_seed") {
 682→        setSeedItems((existing) => {
 683→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
 684→          for (const seed of parsed.seeds) {
 685→            deduped.set(`${seed.id}:${seed.sourceKind}:${seed.sourceId}`, seed);
 686→          }
 687→          return [...deduped.values()];
 688→        });
 689→        return;
 690→      }
 691→
 692→      if (parsed.type === "onboarding_state") {
 693→        setWorkspace((existing) =>
 694→          existing
 695→            ? {
 696→                ...existing,
 697→                onboardingState: parsed.onboardingState,
 698→                onboardingComplete: parsed.onboardingState === "complete",
 699→              }
 700→            : existing,
 701→        );
 702→        return;
 703→      }
 704→
 705→      if (parsed.type === "error") {
 706→        setErrorMessage(parsed.error);
 707→        setIsLoading(false);
 708→        stream.close();
 709→        streamRef.current = undefined;
 710→        return;
 711→      }
 712→
 713→      if (parsed.type === "done") {
 714→        setSessions((existing) =>
 715→          existing.map((session) =>
 716→            session.id === activeSessionId
 717→              ? {
 718→                  ...session,
 719→                  updatedAt: new Date(),
 720→                  conversations: session.conversations.map((conversation) =>
 721→                    conversation.id === clientMessageId
 722→                      ? {
 723→                          ...conversation,
 724→                          response: streamedText,
 725→                          updatedAt: new Date(),
 726→                        }
 727→                      : conversation,
 728→                  ),
 729→                }
 730→              : session,
 731→          ),
 732→        );
 733→
 734→        setIsLoading(false);
 735→        stream.close();
 736→        streamRef.current = undefined;
 737→
 738→        // Refresh sidebar after stream completes
 739→        if (workspace) {
 740→          void refreshSidebar(workspace.id);
 741→        }
 742→      }
 743→    };
 744→
 745→    stream.onerror = () => {
 746→      setErrorMessage("SSE stream disconnected");
 747→      setIsLoading(false);
 748→      stream.close();
 749→      streamRef.current = undefined;
 750→    };
 751→  }
 752→
 753→  function onStopMessage() {
 754→    if (!streamRef.current) {
 755→      return;
 756→    }
 757→
 758→    streamRef.current.close();
 759→    streamRef.current = undefined;
 760→    setIsLoading(false);
 761→  }
 762→
 763→  function renderConversationItem(conv: ConversationSidebarItem, depth: number = 0) {
 764→    return (
 765→      <li key={conv.id}>
 766→        <button
 767→          type="button"
 768→          className={`sidebar-conversation-item${conv.id === activeConversationId ? " sidebar-conversation-item--active" : ""}${depth > 0 ? " sidebar-conversation-item--branch" : ""}`}
 769→          style={depth > 0 ? { paddingLeft: `${8 + depth * 12}px` } : undefined}
 770→          onClick={() => onSelectConversation(conv.id)}
 771→        >
 772→          {depth > 0 ? "\u21b3 " : ""}{conv.title}
 773→        </button>
 774→        {conv.branches && conv.branches.length > 0 ? (
 775→          <ul className="sidebar-conversation-list sidebar-branch-list">
 776→            {conv.branches.map((branch) => renderConversationItem(branch, depth + 1))}
 777→          </ul>
 778→        ) : undefined}
 779→      </li>
 780→    );
 781→  }
 782→
 783→  if (!workspace) {
 784→    return (
 785→      <section className="workspace-setup">
 786→        <h2>Create Workspace</h2>
 787→        <p>Start with workspace name and owner identity. Onboarding continues in chat.</p>
 788→        <form onSubmit={onCreateWorkspace} className="workspace-form">
 789→          <label>
 790→            Workspace name
 791→            <input
 792→              value={createWorkspaceName}
 793→              onChange={(event) => setCreateWorkspaceName(event.target.value)}
 794→              placeholder="Acme Labs"
 795→              required
 796→            />
 797→          </label>
 798→          <label>
 799→            Owner display name
 800→            <input
 801→              value={createOwnerName}
 802→              onChange={(event) => setCreateOwnerName(event.target.value)}
 803→              placeholder="Marcus"
 804→              required
 805→            />
 806→          </label>
 807→          <button type="submit" disabled={!canCreateWorkspace || isCreatingWorkspace || isBootstrapping}>
 808→            {isCreatingWorkspace ? "Creating..." : "Create Workspace"}
 809→          </button>
 810→        </form>
 811→        {errorMessage ? <p className="error-message">{errorMessage}</p> : undefined}
 812→      </section>
 813→    );
 814→  }
 815→
 816→  return (
 817→    <section className="reachat-page">
 818→      <div className="workspace-toolbar">
 819→        <div>
 820→          <strong>{workspace.name}</strong>
 821→        </div>
 822→        <button type="button" className="seed-toggle" onClick={() => setIsSeedPanelOpen((current) => !current)}>
 823→          {isSeedPanelOpen ? "Hide live graph seed" : "Show live graph seed"} ({seedItems.length})
 824→        </button>
 825→        {pendingFile ? (
 826→          <div className="pending-file">
 827→            Attached: {pendingFile.name}
 828→            <button type="button" onClick={() => setPendingFile(undefined)}>
 829→              Clear
 830→            </button>
 831→          </div>
 832→        ) : undefined}
 833→      </div>
 834→
 835→      <div className="workspace-layout">
 836→        <aside className="conversation-sidebar">
 837→          <button
 838→            type="button"
 839→            className="sidebar-new-conversation"
 840→            onClick={onNewConversation}
 841→            disabled={isLoading}
 842→          >
 843→            New conversation
 844→          </button>
 845→
 846→          {sidebar?.groups.map((group) => (
 847→            <div key={group.projectId} className="sidebar-project-group">
 848→              <div className="sidebar-project-header">
 849→                <span className="sidebar-project-name">{group.projectName}</span>
 850→                <span className="sidebar-project-count">{group.conversations.length}</span>
 851→              </div>
 852→              {group.featureActivity.length > 0 ? (
 853→                <div className="sidebar-feature-activity">
 854→                  {group.featureActivity.map((feature) => (
 855→                    <span key={feature.featureId} className="sidebar-feature-chip">
 856→                      {feature.featureName}
 857→                    </span>
 858→                  ))}
 859→                </div>
 860→              ) : undefined}
 861→              <ul className="sidebar-conversation-list">
 862→                {group.conversations.map((conv) => renderConversationItem(conv))}
 863→              </ul>
 864→            </div>
 865→          ))}
 866→
 867→          {sidebar && sidebar.unlinked.length > 0 ? (
 868→            <div className="sidebar-project-group">
 869→              <div className="sidebar-project-header">
 870→                <span className="sidebar-project-name sidebar-unlinked-label">Unlinked</span>
 871→                <span className="sidebar-project-count">{sidebar.unlinked.length}</span>
 872→              </div>
 873→              <ul className="sidebar-conversation-list">
 874→                {sidebar.unlinked.map((conv) => renderConversationItem(conv))}
 875→              </ul>
 876→            </div>
 877→          ) : undefined}
 878→        </aside>
 879→
 880→        <div className={`chat-main${isSeedPanelOpen ? " chat-main--with-seeds" : ""}`}>
 881→          <Chat
 882→            viewType="chat"
 883→            sessions={sessions}
 884→            activeSessionId={activeSession.id}
 885→            components={chatComponentCatalog}
 886→            isLoading={isLoading}
 887→            onSendMessage={onSendMessage}
 888→            onStopMessage={onStopMessage}
 889→            onFileUpload={onUploadFile}
 890→          >
 891→            <SessionMessagePanel>
 892→              <SessionMessagesHeader>
 893→                <div className="reachat-header">
 894→                  Workspace Chat + Extraction
 895→                </div>
 896→              </SessionMessagesHeader>
 897→              <SessionMessages>
 898→                {(conversations) =>
 899→                  conversations.map((conversation, index) => {
 900→                    const isInherited = inheritedMessageIds.has(conversation.id);
 901→                    const isLastInherited = isInherited
 902→                      && index < conversations.length - 1
 903→                      && !inheritedMessageIds.has(conversations[index + 1].id);
 904→                    return (
 905→                      <div
 906→                        key={conversation.id}
 907→                        data-message-id={conversation.id}
 908→                        className={isInherited ? "message-inherited" : undefined}
 909→                      >
 910→                        <SessionMessage
 911→                          conversation={conversation}
 912→                          isLast={index === conversations.length - 1}
 913→                        />
 914→                        {!isInherited && conversation.response && workspace.onboardingState === "complete" ? (
 915→                          <button
 916→                            type="button"
 917→                            className="branch-message-btn"
 918→                            onClick={() => void onBranchFromMessage(conversation.id)}
 919→                            disabled={isLoading || branchingFromId !== undefined}
 920→                            title="Branch from here"
 921→                          >
 922→                            <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
 923→                              <path d="M5 3v4.5c0 1.1.9 2 2 2h2.5M5 3L3 5M5 3l2 2M11 5v4.5c0 1.1-.9 2-2 2H6.5M11 5l-2-2M11 5l2-2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
 924→                            </svg>
 925→                          </button>
 926→                        ) : undefined}
 927→                        {isLastInherited ? (
 928→                          <div className="branch-divider">Branch point</div>
 929→                        ) : undefined}
 930→                      </div>
 931→                    );
 932→                  })
 933→                }
 934→              </SessionMessages>
 935→              <ChatSuggestions
 936→                suggestions={suggestions}
 937→                onSuggestionClick={(suggestion) => {
 938→                  void onSendMessage(suggestion);
 939→                }}
 940→              />
 941→              {workspace.onboardingState === "summary_pending" ? (
 942→                <div className="onboarding-action-buttons">
 943→                  <button
 944→                    type="button"
 945→                    disabled={isLoading}
 946→                    onClick={() =>
 947→                      void onSendMessage("Looks good, let's go.", {
 948→                        onboardingAction: "finalize_onboarding",
 949→                      })}
 950→                  >
 951→                    Looks good, let's go
 952→                  </button>
 953→                  <button
 954→                    type="button"
 955→                    disabled={isLoading}
 956→                    onClick={() =>
 957→                      void onSendMessage("I want to add more.", {
 958→                        onboardingAction: "continue_onboarding",
 959→                      })}
 960→                  >
 961→                    I want to add more
 962→                  </button>
 963→                </div>
 964→              ) : undefined}
 965→              <div onClickCapture={onChatInputClickCapture}>
 966→                <ChatInput
 967→                  ref={chatInputRef}
 968→                  placeholder="Discuss tasks, decisions, and questions..."
 969→                  allowedFiles={[".md", ".txt"]}
 970→                  mentions={{
 971→                    onSearch: searchMentions,
 972→                  }}
 973→                  commands={{
 974→                    items: COMMAND_ITEMS,
 975→                  }}
 976→                />
 977→              </div>
 978→            </SessionMessagePanel>
 979→          </Chat>
 980→
 981→          {isSeedPanelOpen ? (
 982→            <aside className="seed-panel">
 983→              <h3>Live Graph Seed</h3>
 984→              <p>Entities extracted during onboarding and document ingestion.</p>
 985→              <ul>
 986→                {seedItems.map((seed) => (
 987→                  <li key={`${seed.id}:${seed.sourceKind}:${seed.sourceId}`}>
 988→                    <button
 989→                      type="button"
 990→                    >
 991→                      <span className="seed-kind">{seed.kind}</span>
 992→                      <span className="seed-text">{seed.text}</span>
 993→                      <span className="seed-meta">
 994→                        {seed.confidence.toFixed(2)} · {seed.sourceKind}
 995→                      </span>
 996→                      {seed.sourceLabel ? <span className="seed-label">{seed.sourceLabel}</span> : undefined}
 997→                    </button>
 998→                  </li>
 999→                ))}
1000→              </ul>
1001→            </aside>
1002→          ) : undefined}
1003→        </div>
1004→      </div>
1005→
1006→      {errorMessage ? <p className="error-message">{errorMessage}</p> : undefined}
1007→    </section>
1008→  );
1009→}
