197→  }
198→
199→  function handleDismissAll() {
200→    setDismissedAll(true);
201→  }
202→
203→  if (dismissedAll) return undefined;
204→
205→  return (
206→    <section className="work-item-suggestion-list">
207→      <div className="work-item-suggestion-list-header">
208→        <p className="extraction-summary-title">{props.title}</p>
