  1→import { randomUUID } from "node:crypto";
  2→import { RecordId, type Surreal } from "surrealdb";
  3→import { HttpError } from "../http/errors";
  4→
  5→type HasProjectRow = {
  6→  id: RecordId<"has_project", string>;
  7→};
  8→
  9→type HasFeatureRow = {
 10→  id: RecordId<"has_feature", string>;
 11→};
 12→
 13→export type ProjectScopeRow = {
 14→  id: RecordId<"project", string>;
 15→  name: string;
 16→};
 17→
 18→export async function ensureDefaultWorkspaceProjectScope(surreal: Surreal): Promise<void> {
 19→  const now = new Date();
 20→  const workspaceRecord = new RecordId("workspace", "default");
 21→  const projectRecord = new RecordId("project", "brain");
 22→
 23→  const workspace = await surreal.select<{ id: RecordId<"workspace", string> }>(workspaceRecord);
 24→  if (!workspace) {
 25→    await surreal.create(workspaceRecord).content({
 26→      name: "Marcus's Brain",
 27→      status: "active",
 28→      description: "Default dogfooding workspace",
 29→      onboarding_complete: true,
 30→      onboarding_turn_count: 0,
 31→      onboarding_summary_pending: false,
 32→      onboarding_started_at: now,
 33→      onboarding_completed_at: now,
 34→      created_at: now,
 35→      updated_at: now,
 36→    });
 37→  }
 38→
 39→  const project = await surreal.select<{ id: RecordId<"project", string> }>(projectRecord);
 40→  if (!project) {
 41→    await surreal.create(projectRecord).content({
 42→      name: "AI-Native Business Management Platform",
 43→      status: "active",
 44→      description: "Default dogfooding project",
 45→      created_at: now,
 46→      updated_at: now,
 47→    });
 48→  }
 49→
 50→  await ensureWorkspaceProjectEdge(surreal, workspaceRecord, projectRecord, now);
 51→}
 52→
 53→export async function ensureWorkspaceProjectEdge(
 54→  surreal: Surreal,
 55→  workspaceRecord: RecordId<"workspace", string>,
 56→  projectRecord: RecordId<"project", string>,
 57→  now: Date,
 58→): Promise<void> {
 59→  const [edgeRows] = await surreal
 60→    .query<[HasProjectRow[]]>(
 61→      "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
 62→      {
 63→        workspace: workspaceRecord,
 64→        project: projectRecord,
 65→      },
 66→    )
 67→    .collect<[HasProjectRow[]]>();
 68→
 69→  if (edgeRows.length === 0) {
 70→    await surreal.relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
 71→      added_at: now,
 72→    }).output("after");
 73→  }
 74→}
 75→
 76→export async function ensureProjectFeatureEdge(
 77→  surreal: Surreal,
 78→  projectRecord: RecordId<"project", string>,
 79→  featureRecord: RecordId<"feature", string>,
 80→  now: Date,
 81→): Promise<void> {
 82→  const [edgeRows] = await surreal
 83→    .query<[HasFeatureRow[]]>(
 84→      "SELECT id FROM has_feature WHERE `in` = $project AND out = $feature LIMIT 1;",
 85→      {
 86→        project: projectRecord,
 87→        feature: featureRecord,
 88→      },
 89→    )
 90→    .collect<[HasFeatureRow[]]>();
 91→
 92→  if (edgeRows.length === 0) {
 93→    await surreal.relate(projectRecord, new RecordId("has_feature", randomUUID()), featureRecord, {
 94→      added_at: now,
 95→    }).output("after");
 96→  }
 97→}
 98→
 99→export async function resolveWorkspaceRecord(
100→  surreal: Surreal,
101→  workspaceId: string,
102→): Promise<RecordId<"workspace", string>> {
103→  const workspaceRecord = new RecordId("workspace", workspaceId);
104→  const workspace = await surreal.select<{ id: RecordId<"workspace", string> }>(workspaceRecord);
105→  if (!workspace) {
106→    throw new HttpError(404, `workspace not found: ${workspaceId}`);
107→  }
108→  return workspaceRecord;
109→}
110→
111→export async function resolveWorkspaceProjectRecord(
112→  surreal: Surreal,
113→  workspaceRecord: RecordId<"workspace", string>,
114→  projectId: string,
115→): Promise<RecordId<"project", string>> {
116→  const projectRecord = new RecordId("project", projectId);
117→  const project = await surreal.select<{ id: RecordId<"project", string> }>(projectRecord);
118→  if (!project) {
119→    throw new HttpError(404, `project not found: ${projectId}`);
120→  }
121→
122→  const [edgeRows] = await surreal
123→    .query<[HasProjectRow[]]>(
124→      "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
125→      {
126→        workspace: workspaceRecord,
127→        project: projectRecord,
128→      },
129→    )
130→    .collect<[HasProjectRow[]]>();
131→
132→  if (edgeRows.length === 0) {
133→    throw new HttpError(400, "project is not linked to workspace");
134→  }
135→
136→  return projectRecord;
137→}
138→
139→export async function loadWorkspaceProjects(
140→  surreal: Surreal,
141→  workspaceRecord: RecordId<"workspace", string>,
142→): Promise<ProjectScopeRow[]> {
143→  const [rows] = await surreal
144→    .query<[ProjectScopeRow[]]>(
145→      "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
146→      {
147→        workspace: workspaceRecord,
148→      },
149→    )
150→    .collect<[ProjectScopeRow[]]>();
151→
152→  return rows;
153→}
154→
155→export function resolveEntityProject(
156→  entityText: string,
157→  promptText: string,
158→  projects: ProjectScopeRow[],
159→): RecordId<"project", string> | undefined {
160→  if (projects.length === 0) {
161→    return undefined;
162→  }
163→
164→  if (projects.length === 1) {
165→    return projects[0].id;
166→  }
167→
168→  const haystack = `${promptText}\n${entityText}`;
169→  const matchingProjects = projects.filter((project) => {
170→    const escaped = project.name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
171→    return new RegExp(`\\b${escaped}\\b`, "i").test(haystack);
172→  });
173→
174→  if (matchingProjects.length !== 1) {
175→    return undefined;
176→  }
177→
178→  return matchingProjects[0].id;
179→}
180→

