102→        POST: withRequestLogging("POST /api/entities/:entityId/actions", "POST", (request) =>
103→          entityActionsHandler(request.params.entityId, request),
104→        ),
105→      },
106→      "/api/workspaces/:workspaceId/conversations/:parentId/branch": {
107→        POST: withRequestLogging(
108→          "POST /api/workspaces/:workspaceId/conversations/:parentId/branch",
109→          "POST",
110→          (request) =>
111→            branchConversationHandler(
112→              request.params.workspaceId,
113→              request.params.parentId,
114→              request,
115→            ),
116→        ),
117→      },
118→      "/api/workspaces/:workspaceId/work-items/accept": {
119→        POST: withRequestLogging(
120→          "POST /api/workspaces/:workspaceId/work-items/accept",
121→          "POST",
122→          (request) => workItemAcceptHandler(request.params.workspaceId, request),
123→        ),
124→      },
125→      "/api/workspaces/:workspaceId/webhooks/github": {
126→        POST: withRequestLogging(
127→          "POST /api/workspaces/:workspaceId/webhooks/github",
128→          "POST",
129→          (request) => githubWebhookHandler(request.params.workspaceId, request),
130→        ),
131→      },
132→      "/": appHtml,
133→      "/*": appHtml,
134→    },
135→  });
136→
137→  logInfo("server.started", "Brain app server started", {
138→    port: server.port,
139→    host: "127.0.0.1",
140→    assistantModelId: config.assistantModelId,
141→    extractionModelId: config.extractionModelId,
142→    pmModelId: config.pmModelId,
143→    embeddingModelId: config.embeddingModelId,
144→    embeddingDimension: config.embeddingDimension,
145→    extractionStoreThreshold: config.extractionStoreThreshold,
146→    extractionDisplayThreshold: config.extractionDisplayThreshold,
147→    surrealTransport: config.surrealUrl.startsWith("wss://")
148→      ? "wss"
149→      : config.surrealUrl.startsWith("ws://")
150→        ? "ws"
151→        : config.surrealUrl.startsWith("https://")
152→          ? "https"
153→          : "http",
154→    surrealNamespace: config.surrealNamespace,
155→    surrealDatabase: config.surrealDatabase,
156→    openRouterReasoningEnabled: config.openRouterReasoning !== undefined,
157→  });
