 32→  chatInputRef: React.RefObject<ChatInputRef | null>;
 33→  onSendMessage: (message: string, options?: { onboardingAction?: OnboardingAction }) => Promise<void>;
 34→  onStopMessage: () => void;
 35→  onNewConversation: () => void;
 36→  onSelectConversation: (conversationId: string) => void;
 37→  onBranchFromMessage: (messageId: string) => Promise<void>;
 38→  searchMentions: (query: string) => Promise<MentionItem[]>;
 39→  onUploadFile: (file: File) => void;
 40→  onChatInputClickCapture: (event: MouseEvent<HTMLDivElement>) => void;
 41→  setIsSeedPanelOpen: (open: boolean | ((prev: boolean) => boolean)) => void;
