 46→export function useChatSession(
 47→  bootstrapPayload?: WorkspaceBootstrapPayload,
 48→): UseChatSessionReturn {
 49→  const store = useWorkspaceState();
 50→  const workspaceId = store.workspaceId;
 51→  const workspaceName = store.workspaceName;
 52→  const onboardingState = store.onboardingState;
 53→
 54→  const [sessions, setSessions] = useState<Session[]>([
 55→    {
 56→      id: "main",
 57→      title: "Workspace Chat",
 58→      createdAt: new Date(),
 59→      updatedAt: new Date(),
 60→      conversations: [],
 61→    },
 62→  ]);
 63→  const [activeSessionId] = useState("main");
 64→  const [backendConversationId, setBackendConversationId] = useState<string | undefined>();
 65→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 66→  const [isLoading, setIsLoading] = useState(false);
 67→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 68→  const [isSeedPanelOpen, setIsSeedPanelOpen] = useState(false);
 69→  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
 70→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 71→  const [inheritedMessageIds, setInheritedMessageIds] = useState<Set<string>>(new Set());
 72→  const [pendingFile, setPendingFile] = useState<File | undefined>();
 73→  const streamRef = useRef<EventSource | undefined>(undefined);
 74→  const chatInputRef = useRef<ChatInputRef | null>(null);
 75→
 76→  // Track the last applied bootstrap payload to avoid re-applying
 77→  const appliedBootstrapRef = useRef<WorkspaceBootstrapPayload | undefined>(undefined);
 78→
 79→  const activeSession = useMemo(
 80→    () => sessions.find((session) => session.id === activeSessionId),
 81→    [sessions, activeSessionId],
 82→  );
 83→
 84→  if (!activeSession) {
 85→    throw new Error("active session missing");
 86→  }
 87→
 88→  // Apply bootstrap payload when it arrives
 89→  useEffect(() => {
 90→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
 91→      return;
 92→    }
 93→    appliedBootstrapRef.current = bootstrapPayload;
 94→
 95→    setSessions([
 96→      {
 97→        id: "main",
 98→        title: workspaceName ?? "Workspace Chat",
 99→        createdAt: new Date(),
100→        updatedAt: new Date(),
101→        conversations: bootstrapPayload.conversations,
102→      },
103→    ]);
104→    setInheritedMessageIds(bootstrapPayload.inheritedIds);
105→    setSuggestions(
106→      bootstrapPayload.latestSuggestions.map((content, index) => ({
107→        id: `bootstrap-suggestion-${index}-${content}`,
108→        content,
109→      })),
110→    );
111→    setActiveConversationId(store.conversationId);
112→    setBackendConversationId(store.conversationId);
113→  }, [bootstrapPayload]);
114→
115→  // Highlight message support (graph -> chat navigation)
116→  const highlightMessageId = useViewState((s) => s.highlightMessageId);
117→  const clearHighlight = useViewState((s) => s.clearHighlight);
118→
119→  useEffect(() => {
120→    if (!highlightMessageId) return;
121→
122→    const timer = setTimeout(() => {
123→      const element = document.querySelector(`[data-message-id="${highlightMessageId}"]`);
124→      if (element) {
125→        element.scrollIntoView({ behavior: "smooth", block: "center" });
126→        element.classList.add("animate-highlight");
127→        element.addEventListener(
128→          "animationend",
129→          () => {
130→            element.classList.remove("animate-highlight");
131→          },
132→          { once: true },
133→        );
134→      }
135→      clearHighlight();
136→    }, 100);
137→
138→    return () => clearTimeout(timer);
139→  }, [highlightMessageId, clearHighlight]);
140→
141→  async function refreshSidebar(wsId: string) {
142→    try {
143→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
144→      if (response.ok) {
145→        const payload = await response.json();
146→        store.setSidebar(payload);
147→      }
148→    } catch {
149→      // Sidebar refresh is non-critical; silently ignore
150→    }
151→  }
152→
153→  async function loadConversation(wsId: string, conversationId: string) {
154→    try {
155→      const response = await fetch(
156→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
157→      );
158→      if (!response.ok) {
159→        const body = await response.text();
160→        setErrorMessage(body);
161→        return;
162→      }
163→
164→      const payload = (await response.json()) as WorkspaceConversationResponse;
165→      const conversations: Session["conversations"] = [];
166→      let latestSuggestions: string[] = [];
167→      const inheritedIds = new Set<string>();
168→
169→      for (const message of payload.messages) {
170→        if (message.role === "user") {
171→          conversations.push({
172→            id: message.id,
173→            question: message.text,
174→            createdAt: new Date(message.createdAt),
175→          });
176→          if (message.inherited) {
177→            inheritedIds.add(message.id);
178→          }
179→          continue;
180→        }
181→
182→        const last = conversations[conversations.length - 1];
183→        if (last && !last.response) {
184→          last.response = message.text;
185→          last.updatedAt = new Date(message.createdAt);
186→          latestSuggestions =
187→            message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
188→          if (message.inherited) {
189→            inheritedIds.add(last.id);
190→          }
191→          continue;
192→        }
193→
194→        conversations.push({
195→          id: `assistant-${message.id}`,
196→          question: "System kickoff",
197→          response: message.text,
198→          createdAt: new Date(message.createdAt),
199→        });
200→        if (message.inherited) {
201→          inheritedIds.add(`assistant-${message.id}`);
202→        }
203→        latestSuggestions =
204→          message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
205→      }
206→
207→      setInheritedMessageIds(inheritedIds);
208→      setSessions([
209→        {
210→          id: "main",
211→          title: workspaceName ?? "Workspace Chat",
212→          createdAt: new Date(),
213→          updatedAt: new Date(),
214→          conversations,
215→        },
216→      ]);
217→
218→      setSuggestions(
219→        latestSuggestions.map((content, index) => ({
220→          id: `conv-suggestion-${index}-${content}`,
221→          content,
222→        })),
223→      );
224→
225→      setActiveConversationId(conversationId);
226→      setBackendConversationId(conversationId);
227→    } catch (error) {
228→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
229→      setErrorMessage(messageText);
230→    }
231→  }
232→
233→  function onNewConversation() {
234→    setActiveConversationId(undefined);
235→    setBackendConversationId(undefined);
236→    setSessions([
237→      {
238→        id: "main",
239→        title: workspaceName ?? "Workspace Chat",
240→        createdAt: new Date(),
241→        updatedAt: new Date(),
242→        conversations: [],
243→      },
244→    ]);
245→    setSuggestions([]);
246→    setErrorMessage(undefined);
247→  }
248→
249→  function onSelectConversation(conversationId: string) {
250→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
251→      return;
252→    }
253→
254→    void loadConversation(workspaceId, conversationId);
255→  }
256→
257→  async function onBranchFromMessage(messageId: string) {
258→    if (!workspaceId || !activeConversationId || isLoading) return;
259→
260→    setBranchingFromId(messageId);
261→    try {
262→      const response = await fetch(
263→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
264→        {
265→          method: "POST",
266→          headers: { "Content-Type": "application/json" },
267→          body: JSON.stringify({ messageId }),
268→        },
269→      );
270→
271→      if (!response.ok) {
272→        const body = await response.text();
273→        setErrorMessage(body);
274→        return;
275→      }
276→
277→      const payload = (await response.json()) as BranchConversationResponse;
278→      await loadConversation(workspaceId, payload.conversationId);
279→      await refreshSidebar(workspaceId);
280→    } catch (error) {
281→      const messageText = error instanceof Error ? error.message : "Branch creation failed";
282→      setErrorMessage(messageText);
283→    } finally {
284→      setBranchingFromId(undefined);
285→    }
286→  }
287→
288→  async function searchMentions(query: string): Promise<MentionItem[]> {
289→    if (!workspaceId) {
290→      return [];
291→    }
292→
293→    const response = await fetch(
294→      `/api/entities/search?q=${encodeURIComponent(query)}&workspaceId=${encodeURIComponent(workspaceId)}&limit=8`,
295→    );
296→    if (!response.ok) {
297→      throw new Error(`entity search failed: ${response.status}`);
298→    }
299→
300→    const rows = (await response.json()) as SearchEntityResponse[];
301→    return rows.map((row) => ({
302→      id: row.id,
303→      label: `${row.kind}: ${row.text.slice(0, 48)}`,
304→      description: `confidence ${row.confidence.toFixed(2)}`,
305→      value: `@${row.id}`,
306→    }));
307→  }
308→
309→  function onUploadFile(file: File) {
310→    setPendingFile(file);
311→  }
312→
313→  function onChatInputClickCapture(event: MouseEvent<HTMLDivElement>) {
314→    if (!pendingFile || isLoading) {
315→      return;
316→    }
317→
318→    const target = event.target;
319→    if (!(target instanceof Element)) {
320→      return;
321→    }
322→
323→    const sendButton = target.closest("button[title='Send']");
324→    if (!sendButton) {
325→      return;
326→    }
327→
328→    const currentMessage = chatInputRef.current?.getValue().trim() ?? "";
329→    if (currentMessage.length > 0) {
330→      return;
331→    }
332→
333→    event.preventDefault();
334→    event.stopPropagation();
335→    void onSendMessage("");
336→  }
337→
338→  async function onSendMessage(
339→    message: string,
340→    options?: { onboardingAction?: OnboardingAction },
341→  ) {
342→    if (isLoading || !workspaceId) {
343→      return;
344→    }
345→
346→    const text = message.trim();
347→    if (!text && !pendingFile) {
348→      return;
349→    }
350→
351→    setErrorMessage(undefined);
352→    setIsLoading(true);
353→    setSuggestions([]);
354→
355→    const clientMessageId = crypto.randomUUID();
356→    const currentAttachment = pendingFile;
357→
358→    setSessions((existing) =>
359→      existing.map((session) =>
360→        session.id === activeSessionId
361→          ? {
362→              ...session,
363→              updatedAt: new Date(),
364→              conversations: [
365→                ...session.conversations,
366→                {
367→                  id: clientMessageId,
368→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
369→                  createdAt: new Date(),
370→                  ...(currentAttachment
371→                    ? {
372→                        files: [
373→                          {
374→                            name: currentAttachment.name,
375→                            type: currentAttachment.type,
376→                            size: currentAttachment.size,
377→                          },
378→                        ],
379→                      }
380→                    : {}),
381→                },
382→              ],
383→            }
384→          : session,
385→      ),
386→    );
387→
388→    let response: Response;
389→    try {
390→      if (currentAttachment) {
391→        const formData = new FormData();
392→        formData.set("clientMessageId", clientMessageId);
393→        formData.set("workspaceId", workspaceId);
394→        formData.set("text", text);
395→        if (backendConversationId) {
396→          formData.set("conversationId", backendConversationId);
397→        }
398→        if (options?.onboardingAction) {
399→          formData.set("onboardingAction", options.onboardingAction);
400→        }
401→        formData.set("file", currentAttachment);
402→
403→        response = await fetch("/api/chat/messages", {
404→          method: "POST",
405→          body: formData,
406→        });
407→      } else {
408→        response = await fetch("/api/chat/messages", {
409→          method: "POST",
410→          headers: {
411→            "Content-Type": "application/json",
412→          },
413→          body: JSON.stringify({
414→            clientMessageId,
415→            workspaceId,
416→            text,
417→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
418→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
419→          }),
420→        });
421→      }
422→    } catch (error) {
423→      const messageText = error instanceof Error ? error.message : "Network error";
424→      setErrorMessage(messageText);
425→      setIsLoading(false);
426→      return;
427→    } finally {
428→      setPendingFile(undefined);
429→    }
430→
431→    if (!response.ok) {
432→      const body = await response.text();
433→      setErrorMessage(body);
434→      setIsLoading(false);
435→      return;
436→    }
437→
438→    const payload = (await response.json()) as ChatMessageResponse;
439→    const isNewConversation = !backendConversationId;
440→    setBackendConversationId(payload.conversationId);
441→    if (isNewConversation) {
442→      setActiveConversationId(payload.conversationId);
443→    }
444→
445→    if (streamRef.current) {
446→      streamRef.current.close();
447→      streamRef.current = undefined;
448→    }
449→
450→    let streamedText = "";
451→
452→    const stream = new EventSource(payload.streamUrl);
453→    streamRef.current = stream;
454→
455→    stream.onmessage = (messageEvent) => {
456→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
457→
458→      if (parsed.type === "token") {
459→        streamedText = `${streamedText}${parsed.token}`;
460→        setSessions((existing) =>
461→          existing.map((session) =>
462→            session.id === activeSessionId
463→              ? {
464→                  ...session,
465→                  conversations: session.conversations.map((conversation) =>
466→                    conversation.id === clientMessageId
467→                      ? {
468→                          ...conversation,
469→                          response: streamedText,
470→                          updatedAt: new Date(),
471→                        }
472→                      : conversation,
473→                  ),
474→                }
475→              : session,
476→          ),
477→        );
478→        return;
479→      }
480→
481→      if (parsed.type === "extraction") {
482→        store.mergeSeedItems(
483→          parsed.entities.map((entity) => ({
484→            id: entity.id,
485→            kind: entity.kind,
486→            text: entity.text,
487→            confidence: entity.confidence,
488→            sourceKind: entity.sourceKind,
489→            sourceId: entity.sourceId,
490→          })),
491→        );
492→        return;
493→      }
494→
495→      if (parsed.type === "assistant_message") {
496→        streamedText = parsed.text;
497→        setSuggestions(
498→          (parsed.suggestions ?? []).map((content, index) => ({
499→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
500→            content,
501→          })),
502→        );
503→        setSessions((existing) =>
504→          existing.map((session) =>
505→            session.id === activeSessionId
506→              ? {
507→                  ...session,
508→                  conversations: session.conversations.map((conversation) =>
509→                    conversation.id === clientMessageId
510→                      ? {
511→                          ...conversation,
512→                          response: streamedText,
513→                          updatedAt: new Date(),
514→                        }
515→                      : conversation,
516→                  ),
517→                }
518→              : session,
519→          ),
520→        );
521→        return;
522→      }
523→
524→      if (parsed.type === "onboarding_seed") {
525→        store.mergeSeedItems(parsed.seeds);
526→        return;
527→      }
528→
529→      if (parsed.type === "onboarding_state") {
530→        store.setOnboardingState(parsed.onboardingState);
531→        return;
532→      }
533→
534→      if (parsed.type === "error") {
535→        setErrorMessage(parsed.error);
536→        setIsLoading(false);
537→        stream.close();
538→        streamRef.current = undefined;
539→        return;
540→      }
541→
542→      if (parsed.type === "done") {
543→        setSessions((existing) =>
544→          existing.map((session) =>
545→            session.id === activeSessionId
546→              ? {
547→                  ...session,
548→                  updatedAt: new Date(),
549→                  conversations: session.conversations.map((conversation) =>
550→                    conversation.id === clientMessageId
551→                      ? {
552→                          ...conversation,
553→                          response: streamedText,
554→                          updatedAt: new Date(),
555→                        }
556→                      : conversation,
557→                  ),
558→                }
559→              : session,
560→          ),
561→        );
562→
563→        setIsLoading(false);
564→        stream.close();
565→        streamRef.current = undefined;
566→
567→        // Refresh sidebar after stream completes
568→        if (workspaceId) {
569→          void refreshSidebar(workspaceId);
570→        }
571→      }
572→    };
573→
574→    stream.onerror = () => {
575→      setErrorMessage("SSE stream disconnected");
576→      setIsLoading(false);
577→      stream.close();
578→      streamRef.current = undefined;
579→    };
580→  }
581→
582→  function onStopMessage() {
583→    if (!streamRef.current) {
584→      return;
585→    }
586→
587→    streamRef.current.close();
588→    streamRef.current = undefined;
589→    setIsLoading(false);
590→  }
591→
592→  return {
593→    sessions,
594→    activeSessionId,
595→    activeSession,
596→    activeConversationId,
597→    isLoading,
598→    errorMessage,
599→    suggestions,
600→    pendingFile,
601→    branchingFromId,
602→    inheritedMessageIds,
603→    isSeedPanelOpen,
604→    chatInputRef,
605→    onSendMessage,
606→    onStopMessage,
607→    onNewConversation,
608→    onSelectConversation,
609→    onBranchFromMessage,
610→    searchMentions,
611→    onUploadFile,
612→    onChatInputClickCapture,
613→    setIsSeedPanelOpen,
614→    setErrorMessage,
615→    refreshSidebar,
616→  };
617→}
