 94→type WorkItemStatus = "pending" | "accepting" | "accepted" | "dismissed";
 95→
 96→async function acceptWorkItem(
 97→  workspaceId: string,
 98→  item: WorkItemSuggestionProps,
 99→): Promise<{ entityId: string }> {
100→  const response = await fetch(`/api/workspaces/${workspaceId}/work-items/accept`, {
101→    method: "POST",
102→    headers: { "Content-Type": "application/json" },
103→    body: JSON.stringify({
104→      kind: item.kind,
105→      title: item.title,
106→      rationale: item.rationale,
107→      ...(item.project ? { project: item.project } : {}),
108→      ...(item.priority ? { priority: item.priority } : {}),
109→      ...(item.category ? { category: item.category } : {}),
110→    }),
111→  });
112→  if (!response.ok) {
113→    throw new Error(`accept failed: ${response.status}`);
114→  }
115→  return response.json();
116→}
117→
118→function WorkItemSuggestion(props: WorkItemSuggestionProps) {
119→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
120→  const [status, setStatus] = useState<WorkItemStatus>("pending");
121→
122→  async function handleAccept() {
123→    if (!workspaceId || status !== "pending") return;
124→    setStatus("accepting");
125→    try {
126→      await acceptWorkItem(workspaceId, props);
127→      setStatus("accepted");
128→    } catch {
129→      setStatus("pending");
130→    }
131→  }
132→
133→  function handleDismiss() {
134→    setStatus("dismissed");
135→  }
136→
137→  if (status === "dismissed") return undefined;
138→
139→  const isDuplicate = props.possibleDuplicateId !== undefined;
140→
141→  return (
142→    <article className={`work-item-suggestion ${status === "accepted" ? "work-item-suggestion--accepted" : ""}`}>
143→      <div className="work-item-suggestion-header">
144→        <div style={{ display: "flex", alignItems: "center", gap: "0.3rem" }}>
145→          <span className="entity-kind">{props.kind === "task" ? "Task" : "Feature"}</span>
146→          {props.category ? <CategoryBadge category={props.category} /> : undefined}
147→          {props.priority ? <span className="work-item-priority">{props.priority}</span> : undefined}
148→        </div>
149→        {status === "accepted" ? (
150→          <span className="work-item-accepted-badge">Accepted</span>
151→        ) : (
152→          <div className="work-item-actions">
153→            <button
154→              type="button"
155→              className="work-item-btn work-item-btn--accept"
156→              onClick={handleAccept}
157→              disabled={status === "accepting"}
158→            >
159→              {status === "accepting" ? "..." : "Accept"}
160→            </button>
161→            <button
162→              type="button"
163→              className="work-item-btn work-item-btn--dismiss"
164→              onClick={handleDismiss}
165→            >
166→              Dismiss
167→            </button>
168→          </div>
169→        )}
170→      </div>
171→      <p className="entity-name">{props.title}</p>
172→      <p className="work-item-rationale">{props.rationale}</p>
173→      {isDuplicate ? (
174→        <p className="work-item-duplicate-hint">
175→          Similar to existing: {props.possibleDuplicateName} ({((props.possibleDuplicateSimilarity ?? 0) * 100).toFixed(0)}% match)
176→        </p>
177→      ) : undefined}
178→      {props.project ? <p className="work-item-project">Project: {props.project}</p> : undefined}
179→    </article>
180→  );
181→}
