183→function WorkItemSuggestionList(props: WorkItemSuggestionListProps) {
184→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
185→  const [allStatus, setAllStatus] = useState<"idle" | "accepting">("idle");
186→  const [dismissedAll, setDismissedAll] = useState(false);
187→
188→  async function handleAcceptAll() {
189→    if (!workspaceId || allStatus === "accepting") return;
190→    setAllStatus("accepting");
191→    try {
192→      await Promise.all(props.items.map((item) => acceptWorkItem(workspaceId, item)));
193→    } catch {
194→      // individual items handle their own state
195→    }
196→    setAllStatus("idle");
197→  }
198→
199→  function handleDismissAll() {
200→    setDismissedAll(true);
201→  }
202→
203→  if (dismissedAll) return undefined;
204→
205→  return (
206→    <section className="work-item-suggestion-list">
207→      <div className="work-item-suggestion-list-header">
208→        <p className="extraction-summary-title">{props.title}</p>
209→        <div className="work-item-actions">
210→          <button
211→            type="button"
212→            className="work-item-btn work-item-btn--accept"
213→            onClick={handleAcceptAll}
214→            disabled={allStatus === "accepting"}
215→          >
216→            {allStatus === "accepting" ? "Accepting..." : "Accept All"}
217→          </button>
218→          <button
219→            type="button"
220→            className="work-item-btn work-item-btn--dismiss"
221→            onClick={handleDismissAll}
222→          >
223→            Dismiss All
224→          </button>
225→        </div>
226→      </div>
227→      <div className="extraction-summary-grid">
228→        {props.items.map((item) => (
229→          <WorkItemSuggestion key={`${item.kind}:${item.title}`} {...item} />
