  2→import { GraphCanvas, type GraphCanvasRef } from "reagraph";
  3→import type { GraphResponse, ReagraphEdge } from "../../../shared/contracts";
  4→import { edgeStyle } from "./graph-theme";
  5→
  6→export function KnowledgeGraph({
  7→  workspaceId,
  8→  projectId,
  9→  centerId,
 10→  depth,
 11→  selectedId,
 12→  onNodeClick,
 13→}: {
 14→  workspaceId: string;
 15→  projectId?: string;
 16→  centerId?: string;
 17→  depth: number;
 18→  selectedId?: string;
 19→  onNodeClick: (nodeId: string) => void;
 20→}) {
 21→  const [data, setData] = useState<GraphResponse | undefined>();
 22→  const [loading, setLoading] = useState(true);
 23→  const [error, setError] = useState<string | undefined>();
 24→  const graphRef = useRef<GraphCanvasRef>(null);
 25→
 26→  useEffect(() => {
 27→    setLoading(true);
 28→    setError(undefined);
 29→
 30→    const params = new URLSearchParams();
 31→    if (centerId) {
 32→      params.set("center", centerId);
 33→      params.set("depth", String(depth));
 34→    } else if (projectId) {
 35→      params.set("project", projectId);
 36→    }
 37→
 38→    const url = `/api/graph/${encodeURIComponent(workspaceId)}${params.toString() ? `?${params}` : ""}`;
 39→
 40→    fetch(url)
 41→      .then(async (response) => {
 42→        if (!response.ok) {
 43→          throw new Error(await response.text());
 44→        }
 45→        return response.json() as Promise<GraphResponse>;
 46→      })
 47→      .then((result) => {
 48→        setData(result);
 49→        setLoading(false);
 50→      })
 51→      .catch((err) => {
 52→        setError(err instanceof Error ? err.message : "Failed to load graph");
 53→        setLoading(false);
 54→      });
 55→  }, [workspaceId, projectId, centerId, depth]);
 56→
 57→  if (loading) {
 58→    return (
 59→      <div className="graph-canvas">
 60→        <div className="graph-empty">Loading graph...</div>
 61→      </div>
 62→    );
 63→  }
 64→
 65→  if (error) {
 66→    return (
 67→      <div className="graph-canvas">
 68→        <div className="graph-empty">{error}</div>
 69→      </div>
 70→    );
 71→  }
 72→
 73→  if (!data || (data.nodes.length === 0)) {
 74→    return (
 75→      <div className="graph-canvas">
 76→        <div className="graph-empty">
 77→          <p>Your graph will grow as you have more conversations.</p>
 78→        </div>
 79→      </div>
 80→    );
 81→  }
 82→
 83→  const styledEdges: ReagraphEdge[] = data.edges.map((edge) => {
 84→    const style = edgeStyle(edge.data.type);
 85→    return {
 86→      ...edge,
 87→      fill: style.stroke,
 88→      opacity: style.opacity,
 89→    } as ReagraphEdge;
 90→  });
 91→
 92→  return (
 93→    <div className="graph-canvas">
 94→      <GraphCanvas
 95→        ref={graphRef}
 96→        nodes={data.nodes as any}
 97→        edges={styledEdges as any}
 98→        selections={selectedId ? [selectedId.includes(":") ? selectedId.slice(selectedId.indexOf(":") + 1) : selectedId] : []}
 99→        layoutType="forceDirected2d"
100→        sizingType="attribute"
101→        sizingAttribute="connectionCount"
102→        labelType="auto"
103→        onNodeClick={(node: { id: string }) => {
104→          const match = data.nodes.find((n) => n.id === node.id);
105→          const prefixed = match ? `${match.data.kind}:${node.id}` : node.id;
106→          onNodeClick(prefixed);
107→        }}
108→      />
109→    </div>
110→  );
111→}
