 25→function parseBootstrapMessages(payload: WorkspaceBootstrapResponse): BootstrapPayload {
 26→  const conversations: Session["conversations"] = [];
 27→  let latestSuggestions: string[] = [];
 28→  const inheritedIds = new Set<string>();
 29→
 30→  for (const message of payload.messages) {
 31→    if (message.role === "user") {
 32→      conversations.push({
 33→        id: message.id,
 34→        question: message.text,
 35→        createdAt: new Date(message.createdAt),
 36→      });
 37→      if (message.inherited) {
 38→        inheritedIds.add(message.id);
 39→      }
 40→      continue;
 41→    }
 42→
 43→    const last = conversations[conversations.length - 1];
 44→    if (last && !last.response) {
 45→      last.response = message.text;
 46→      last.updatedAt = new Date(message.createdAt);
 47→      latestSuggestions =
 48→        message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
 49→      if (message.inherited) {
 50→        inheritedIds.add(last.id);
 51→      }
 52→      continue;
 53→    }
 54→
 55→    conversations.push({
 56→      id: `assistant-${message.id}`,
 57→      question: "System kickoff",
 58→      response: message.text,
 59→      createdAt: new Date(message.createdAt),
 60→    });
 61→    if (message.inherited) {
 62→      inheritedIds.add(`assistant-${message.id}`);
 63→    }
 64→    latestSuggestions =
 65→      message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
 66→  }
