 73→export function useWorkspace(): UseWorkspaceReturn {
 74→  const store = useWorkspaceState();
 75→  const [createWorkspaceName, setCreateWorkspaceName] = useState("");
 76→  const [createOwnerName, setCreateOwnerName] = useState("");
 77→  const [isCreatingWorkspace, setIsCreatingWorkspace] = useState(false);
 78→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 79→
 80→  const canCreateWorkspace =
 81→    createWorkspaceName.trim().length > 0 && createOwnerName.trim().length > 0;
 82→
 83→  useEffect(() => {
 84→    const existingWorkspaceId = window.localStorage.getItem(ACTIVE_WORKSPACE_STORAGE_KEY);
 85→    if (!existingWorkspaceId) {
 86→      return;
 87→    }
 88→
 89→    void bootstrapWorkspace(existingWorkspaceId);
 90→  }, []);
 91→
 92→  async function bootstrapWorkspace(workspaceId: string) {
 93→    store.setIsBootstrapping(true);
 94→    setErrorMessage(undefined);
 95→
 96→    let response: Response;
 97→    try {
 98→      response = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/bootstrap`);
 99→    } catch (error) {
100→      const messageText = error instanceof Error ? error.message : "Network error";
101→      setErrorMessage(messageText);
102→      store.setIsBootstrapping(false);
103→      return;
104→    }
105→
106→    if (!response.ok) {
107→      if (response.status === 404) {
108→        window.localStorage.removeItem(ACTIVE_WORKSPACE_STORAGE_KEY);
109→        store.clearWorkspace();
110→      }
111→      const body = await response.text();
112→      setErrorMessage(body);
113→      store.setIsBootstrapping(false);
114→      return;
115→    }
116→
117→    const payload = (await response.json()) as WorkspaceBootstrapResponse;
118→    applyBootstrapPayload(payload);
119→    store.setIsBootstrapping(false);
120→  }
121→
122→  function applyBootstrapPayload(payload: WorkspaceBootstrapResponse) {
123→    const parsed = parseBootstrapMessages(payload);
124→
125→    store.setSeedItems(payload.seeds);
126→    store.setSidebar(payload.sidebar);
127→    store.setBootstrapPayload(parsed);
128→    store.applyWorkspace({
129→      id: payload.workspaceId,
130→      name: payload.workspaceName,
131→      onboardingComplete: payload.onboardingComplete,
132→      onboardingState: payload.onboardingState,
133→      conversationId: payload.conversationId,
134→    });
135→  }
136→
137→  async function onCreateWorkspace(event: FormEvent<HTMLFormElement>) {
138→    event.preventDefault();
139→
140→    const name = createWorkspaceName.trim();
141→    const ownerDisplayName = createOwnerName.trim();
142→    if (isCreatingWorkspace) {
143→      return;
144→    }
145→
146→    if (!name || !ownerDisplayName) {
147→      setErrorMessage("Workspace name and owner display name are required");
148→      return;
149→    }
150→
151→    setErrorMessage(undefined);
152→    setIsCreatingWorkspace(true);
153→
154→    const requestBody: CreateWorkspaceRequest = {
155→      name,
156→      ownerDisplayName,
157→    };
158→
159→    try {
160→      const response = await fetch("/api/workspaces", {
161→        method: "POST",
162→        headers: {
163→          "Content-Type": "application/json",
164→        },
165→        body: JSON.stringify(requestBody),
166→      });
167→
168→      if (!response.ok) {
169→        const body = await response.text();
170→        setErrorMessage(body);
171→        return;
172→      }
173→
174→      const payload = (await response.json()) as Partial<CreateWorkspaceResponse>;
175→      if (typeof payload.workspaceId !== "string" || payload.workspaceId.trim().length === 0) {
176→        throw new Error("create workspace response is missing workspaceId");
177→      }
178→
179→      window.localStorage.setItem(ACTIVE_WORKSPACE_STORAGE_KEY, payload.workspaceId);
180→      await bootstrapWorkspace(payload.workspaceId);
181→      setCreateWorkspaceName("");
182→      setCreateOwnerName("");
183→    } catch (error) {
184→      const messageText = error instanceof Error ? error.message : "Workspace creation failed";
185→      setErrorMessage(messageText);
186→    } finally {
187→      setIsCreatingWorkspace(false);
188→    }
189→  }
190→
191→  return {
192→    isReady: store.workspaceId !== undefined && !store.isBootstrapping,
193→    isBootstrapping: store.isBootstrapping,
194→    isCreatingWorkspace,
195→    errorMessage,
196→    createWorkspaceName,
197→    createOwnerName,
198→    canCreateWorkspace,
199→    setCreateWorkspaceName,
200→    setCreateOwnerName,
201→    onCreateWorkspace,
202→  };
203→}
