1625→export async function getFocusedGraphView(input: {
1626→  surreal: Surreal;
1627→  workspaceRecord: RecordId<"workspace", string>;
1628→  centerEntityRecord: GraphEntityRecord;
1629→  depth: number;
1630→}): Promise<GraphViewRawResult> {
1631→  const clampedDepth = Math.max(1, Math.min(3, input.depth));
1632→
1633→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.centerEntityRecord);
1634→  if (!scoped) {
1635→    throw new Error("entity is outside the current workspace scope");
1636→  }
1637→
1638→  const collected = new Map<string, GraphEntityRecord>();
1639→  collected.set(toRecordIdString(input.centerEntityRecord), input.centerEntityRecord);
1640→
1641→  let frontier: RecordId<string, string>[] = [input.centerEntityRecord];
1642→
1643→  for (let hop = 0; hop < clampedDepth; hop++) {
1644→    if (frontier.length === 0) {
1645→      break;
1646→    }
1647→
1648→    const [rows] = await input.surreal
1649→      .query<[EntityRelationRow[]]>(
1650→        [
1651→          "SELECT id, `in`, out, kind, confidence",
1652→          "FROM entity_relation",
1653→          "WHERE `in` IN $currentIds OR out IN $currentIds;",
1654→        ].join(" "),
1655→        { currentIds: frontier },
1656→      )
1657→      .collect<[EntityRelationRow[]]>();
1658→
1659→    const nextFrontier: RecordId<string, string>[] = [];
1660→
1661→    for (const row of rows) {
1662→      for (const endpoint of [row.in, row.out]) {
1663→        const key = toRecordIdString(endpoint);
1664→        if (collected.has(key)) {
1665→          continue;
1666→        }
1667→
1668→        const inScope = await isEntityInWorkspace(input.surreal, input.workspaceRecord, endpoint);
1669→        if (!inScope) {
1670→          continue;
1671→        }
1672→
1673→        collected.set(key, endpoint);
1674→        nextFrontier.push(endpoint);
1675→      }
1676→    }
1677→
1678→    frontier = nextFrontier;
1679→  }
1680→
1681→  const allRecords = Array.from(collected.values());
1682→  const entities = await resolveEntityNames(input.surreal, allRecords);
1683→  const edges = await collectEntityRelationEdges(input.surreal, allRecords);
1684→
1685→  return { entities, edges };
1686→}
