.feed-section {
  border: 1px solid #d6e4f6;
  border-radius: 14px;
  background: #fbfdff;
  overflow: hidden;
}

.feed-section-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.55rem 0.75rem;
  border-bottom: 1px solid #e2ecf7;
