.feed-item-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.3rem;
  padding-top: 0.25rem;
}

.feed-action-btn {
  border: 1px solid #9fbfe4;
  border-radius: 6px;
  background: #fff;
  color: #1c4f86;
  padding: 0.25rem 0.5rem;
  font-size: 0.72rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s;
}

.feed-action-btn:hover {
  background: #e8f1fd;
}

.feed-action-btn--confirm {
  background: #0057cc;
