}

.feed-action-btn--complete {
  background: #16a34a;
  color: #fff;
  border-color: #16a34a;
}

.feed-action-btn--complete:hover {
  background: #15803d;
}

.feed-action-btn--discuss {
  background: transparent;
  color: #0057cc;
  border-color: #c8d9ef;
}

.feed-action-btn--discuss:hover {
  background: #e8f1fd;
}

