 96→type WorkItemStatus = "pending" | "accepting" | "accepted" | "dismissed";
 97→
 98→async function acceptWorkItem(
 99→  workspaceId: string,
100→  item: WorkItemSuggestionProps,
101→): Promise<{ entityId: string }> {
102→  const response = await fetch(`/api/workspaces/${workspaceId}/work-items/accept`, {
103→    method: "POST",
104→    headers: { "Content-Type": "application/json" },
105→    body: JSON.stringify({
106→      kind: item.kind,
107→      title: item.title,
108→      rationale: item.rationale,
109→      ...(item.project ? { project: item.project } : {}),
110→      ...(item.priority ? { priority: item.priority } : {}),
111→      ...(item.category ? { category: item.category } : {}),
112→    }),
113→  });
114→  if (!response.ok) {
115→    throw new Error(`accept failed: ${response.status}`);
116→  }
117→  return response.json();
118→}
