120→function WorkItemSuggestion(props: WorkItemSuggestionProps) {
121→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
122→  const [status, setStatus] = useState<WorkItemStatus>("pending");
123→
124→  async function handleAccept() {
125→    if (!workspaceId || status !== "pending") return;
126→    setStatus("accepting");
127→    try {
128→      await acceptWorkItem(workspaceId, props);
129→      setStatus("accepted");
130→    } catch {
131→      setStatus("pending");
132→    }
133→  }
134→
135→  function handleDismiss() {
136→    setStatus("dismissed");
137→  }
138→
139→  if (status === "dismissed") return undefined;
140→
141→  const isDuplicate = props.possibleDuplicateId !== undefined;
142→
143→  return (
144→    <article className={`work-item-suggestion ${status === "accepted" ? "work-item-suggestion--accepted" : ""}`}>
145→      <div className="work-item-suggestion-header">
146→        <div style={{ display: "flex", alignItems: "center", gap: "0.3rem" }}>
147→          <span className="entity-kind">{props.kind === "task" ? "Task" : "Feature"}</span>
148→          {props.category ? <CategoryBadge category={props.category} /> : undefined}
149→          {props.priority ? <span className="work-item-priority">{props.priority}</span> : undefined}
150→        </div>
151→        {status === "accepted" ? (
152→          <span className="work-item-accepted-badge">Accepted</span>
153→        ) : (
154→          <div className="work-item-actions">
155→            <button
156→              type="button"
157→              className="work-item-btn work-item-btn--accept"
158→              onClick={handleAccept}
159→              disabled={status === "accepting"}
160→            >
161→              {status === "accepting" ? "..." : "Accept"}
162→            </button>
163→            <button
164→              type="button"
165→              className="work-item-btn work-item-btn--dismiss"
166→              onClick={handleDismiss}
167→            >
168→              Dismiss
169→            </button>
170→          </div>
171→        )}
172→      </div>
173→      <p className="entity-name">{props.title}</p>
174→      <p className="work-item-rationale">{props.rationale}</p>
175→      {isDuplicate ? (
176→        <p className="work-item-duplicate-hint">
177→          Similar to existing: {props.possibleDuplicateName} ({((props.possibleDuplicateSimilarity ?? 0) * 100).toFixed(0)}% match)
178→        </p>
179→      ) : undefined}
180→      {props.project ? <p className="work-item-project">Project: {props.project}</p> : undefined}
181→    </article>
182→  );
183→}
184→
185→function WorkItemSuggestionList(props: WorkItemSuggestionListProps) {
186→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
187→  const [allStatus, setAllStatus] = useState<"idle" | "accepting">("idle");
188→  const [dismissedAll, setDismissedAll] = useState(false);
189→
190→  async function handleAcceptAll() {
191→    if (!workspaceId || allStatus === "accepting") return;
192→    setAllStatus("accepting");
193→    try {
194→      await Promise.all(props.items.map((item) => acceptWorkItem(workspaceId, item)));
195→    } catch {
196→      // individual items handle their own state
197→    }
198→    setAllStatus("idle");
199→  }
200→
201→  function handleDismissAll() {
202→    setDismissedAll(true);
203→  }
204→
205→  if (dismissedAll) return undefined;
206→
207→  return (
208→    <section className="work-item-suggestion-list">
209→      <div className="work-item-suggestion-list-header">
210→        <p className="extraction-summary-title">{props.title}</p>
211→        <div className="work-item-actions">
212→          <button
213→            type="button"
214→            className="work-item-btn work-item-btn--accept"
215→            onClick={handleAcceptAll}
216→            disabled={allStatus === "accepting"}
217→          >
218→            {allStatus === "accepting" ? "Accepting..." : "Accept All"}
219→          </button>
220→          <button
221→            type="button"
222→            className="work-item-btn work-item-btn--dismiss"
223→            onClick={handleDismissAll}
224→          >
225→            Dismiss All
226→          </button>
227→        </div>
228→      </div>
229→      <div className="extraction-summary-grid">
230→        {props.items.map((item) => (
231→          <WorkItemSuggestion key={`${item.kind}:${item.title}`} {...item} />
232→        ))}
233→      </div>
234→    </section>
235→  );
236→}
