  1→import { tool } from "ai";
  2→import { z } from "zod";
  3→import {
  4→  getFocusedGraphView,
  5→  parseRecordIdString,
  6→  type GraphEntityTable,
  7→  type GraphViewRawResult,
  8→} from "../../graph/queries";
  9→import { requireToolContext } from "./helpers";
 10→import type { ChatToolDeps } from "./types";
 11→
 12→function titleCase(s: string): string {
 13→  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
 14→}
 15→
 16→function mergeGraphResults(results: GraphViewRawResult[]): GraphViewRawResult {
 17→  const entityMap = new Map<string, GraphViewRawResult["entities"][number]>();
 18→  const edgeMap = new Map<string, GraphViewRawResult["edges"][number]>();
 19→
 20→  for (const result of results) {
 21→    for (const entity of result.entities) {
 22→      entityMap.set(entity.id, entity);
 23→    }
 24→    for (const edge of result.edges) {
 25→      edgeMap.set(edge.id, edge);
 26→    }
 27→  }
 28→
 29→  return {
 30→    entities: Array.from(entityMap.values()),
 31→    edges: Array.from(edgeMap.values()),
 32→  };
 33→}
 34→
 35→const ENTITY_TABLES: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question"];
 36→
 37→export function createShowRelationshipGraphTool(deps: ChatToolDeps) {
 38→  return tool({
 39→    description:
 40→      "Show an interactive relationship graph for 1-3 entities, visualizing their neighborhood connections. Returns an InlineRelationshipGraph component block for the chat UI.",
 41→    inputSchema: z.object({
 42→      entity_ids: z
 43→        .array(z.string().min(1).describe("Entity record ID, e.g. decision:abc123"))
 44→        .min(1)
 45→        .max(3)
 46→        .describe("Entity IDs to show neighborhoods for (1-3)"),
 47→    }),
 48→    execute: async (input, options) => {
 49→      const context = requireToolContext(options);
 50→
 51→      const entityRecords = input.entity_ids.map((id) =>
 52→        parseRecordIdString(id, ENTITY_TABLES) as ReturnType<typeof parseRecordIdString<GraphEntityTable>>,
 53→      );
 54→
 55→      const rawResults = await Promise.all(
 56→        entityRecords.map((record) =>
 57→          getFocusedGraphView({
 58→            surreal: deps.surreal,
 59→            workspaceRecord: context.workspaceRecord,
 60→            centerEntityRecord: record,
 61→            depth: 1,
 62→          }),
 63→        ),
 64→      );
 65→
 66→      const merged = mergeGraphResults(rawResults);
 67→
 68→      const focusNodeIds = entityRecords.map((r) => r.id as string);
 69→
 70→      const nodes = merged.entities.map((entity) => ({
 71→        id: entity.id,
 72→        label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
 73→        kind: entity.kind,
 74→      }));
 75→
 76→      const edges = merged.edges.map((edge) => ({
 77→        id: edge.id,
 78→        source: edge.fromId,
 79→        target: edge.toId,
 80→        label: titleCase(edge.kind.replace(/_/g, " ")),
 81→        type: edge.kind,
 82→      }));
 83→
 84→      const entityNames = input.entity_ids
 85→        .map((id) => {
 86→          const entity = merged.entities.find((e) => e.id === id.split(":")[1]);
 87→          return entity?.name ?? id;
 88→        })
 89→        .join(", ");
 90→
 91→      return {
 92→        component: "InlineRelationshipGraph",
 93→        props: {
 94→          title: `Relationships: ${entityNames}`,
 95→          nodes,
 96→          edges,
 97→          focusNodeIds,
 98→        },
 99→      };
100→    },
101→  });
102→}
