/* --- Search page --- */

.search-page {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  min-height: 72vh;
  padding: 0.75rem;
}

.search-input-wrapper {
  display: flex;
}

.search-input {
  width: 100%;
  border: 1px solid #b8d0ee;
  border-radius: 12px;
  padding: 0.65rem 0.85rem;
  font-size: 0.9rem;
  color: #13263f;
  background: #fff;
  outline: none;
  transition: border-color 0.15s;
}

.search-input:focus {
  border-color: #0057cc;
  box-shadow: 0 0 0 2px rgba(0, 87, 204, 0.12);
}

.search-input::placeholder {
  color: #8ba0b8;
}

.search-filters {
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem;
}

.search-filter-chip {
  border: 1px solid #c8d9ef;
  border-radius: 999px;
  background: #fff;
  color: #2a4a6b;
  padding: 0.3rem 0.65rem;
  font-size: 0.76rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s, color 0.15s;
}

.search-filter-chip:hover {
  background: #e8f1fd;
  border-color: #9fbfe4;
}

.search-filter-chip--active {
  background: #d0e3fc;
  border-color: #0057cc;
  color: #0e3d6e;
}

.search-results {
  display: grid;
  gap: 0.5rem;
}

.search-result-card {
  border: 1px solid #d6e4f6;
  border-radius: 10px;
  background: #fff;
  padding: 0.6rem 0.7rem;
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
}

.search-result-card:hover {
  border-color: #9fbfe4;
  box-shadow: 0 2px 8px rgba(0, 36, 85, 0.06);
}

.search-result-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.4rem;
}

.search-result-confidence {
  font-size: 0.7rem;
  font-weight: 600;
  color: #476482;
}

.search-result-text {
  margin: 0;
  font-size: 0.84rem;
  font-weight: 600;
  color: #1d3f62;
  line-height: 1.4;
}

.search-result-footer {
  display: flex;
  justify-content: flex-end;
}

.search-result-graph-btn {
  border: 1px solid #9fbfe4;
  border-radius: 8px;
  background: #fff;
  color: #0057cc;
  padding: 0.28rem 0.55rem;
  font-size: 0.72rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s;
}

.search-result-graph-btn:hover {
  background: #e8f1fd;
}

.search-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 30vh;
  color: #4c6583;
  font-size: 0.88rem;
}

.search-empty p {
  margin: 0;
}

